mapper.select:
SELECT pbdd.id, pbdd.taskId, pbdd.`projectId`, pbdd.`projectType`, pbdd.`deliverableName`, pbdd.`deliverId`, pbdd.`deliverablePath`, fbd.`basicDataName` as deliverableType, IFNULL( concat(pbdd.uploadUser, "-", ui.realName), pbdd.uploadUser ) as uploadUser, pbdd.uploadTime, pt.taskName, pt.customInfo as taskCustomInfo FROM `pm_basic_deliver_detail` pbdd inner JOIN `pm_basic_prj_deliver` pbpd ON pbpd.id = pbdd.`deliverId` LEFT JOIN fnd_basic_data fbd ON fbd.`dataTypeCode` = pbpd.`dataTypeCodeSon` AND fbd.`basicDataId` = pbpd.`basicDataIdSon` left join pm_project_task pt on pt.`taskId` = pbdd.`taskId` LEFT JOIN t_user u ON u.`user_name` = pbdd.`uploadUser` LEFT JOIN t_user_info ui ON ui.`user_id` = u.`user_id` and ui.`compID` = #{orgId}
AND pbdd.projectId = #{projectId} AND pbdd.taskId = #{taskId}
#{item}
AND pbdd.`effectiveFrom` <= NOW() AND (pbdd.`effectiveTo` > NOW() OR pbdd.`effectiveTo` IS NULL)
order by pbdd.uploadTime desc

select count(pm.id) > 0 and count(ui.id) > 0 as `all`, count(pm.id) > 0 as edit, count(ui.id) > 0 view, max(ph.projectState) as maxState, group_concat(distinct pm.memberRole) memberRoles, #{permissionTypes} as permissionTypes from pm_project ph left join pm_project_task pt on pt.projectId = ph.projectId and pt.projectType = ph.projectType left join pm_project_member pm on ph.projectId = pm.projectId and pm.effectiveFrom <= now() and ( pm.effectiveTo > now() or pm.effectiveTo is null ) and pm.memberCode = #{user.userName}
left join t_user_info ui on ui.`id` = #{user.userInfoId}
AND FIND_IN_SET(ph.`column001`, #{model.officeCodes}) and find_in_set(ph.`column001`, ui.`custom5`)
and find_in_set(ph.projectType, ui.custom4) where ( pm.memberCode = #{user.userName} or ui.id = #{user.userInfoId} )
AND pt.taskId = #{model.taskId}
AND ph.projectId = #{model.projectId}
AND FIND_IN_SET(ph.projectId, #{model.projectIds})
AND FIND_IN_SET(ph.projectType, #{model.projectType})
AND FIND_IN_SET(ph.`column001`, #{model.officeCodes})
